    "  private ExtractionInfo extractMultilineTextualBlock(JsDocToken token,
                                                      WhitespaceOption option) {

    if (token == JsDocToken.EOC || token == JsDocToken.EOL ||
        token == JsDocToken.EOF) {
      return new ExtractionInfo("", token);
    }

    stream.update();
    int startLineno = stream.getLineno();
    int startCharno = stream.getCharno() + 1;

    // Read the content from the first line.
    String line = stream.getRemainingJSDocLine();
    if (option != WhitespaceOption.PRESERVE) {
      line = line.trim();
    }

    StringBuilder builder = new StringBuilder();
    builder.append(line);

    state = State.SEARCHING_ANNOTATION;
    token = next();

    boolean ignoreStar = false;

    // Track the start of the line to count whitespace that
    // the tokenizer skipped. Because this case is rare, it's easier
    // to do this here than in the tokenizer.

    do {
      switch (token) {
        case STAR:
          if (ignoreStar) {
            // Mark the position after the star as the new start of the line by
            // accounting for any skipped whitespace after the '*'.
            int starCharno = stream.getCharno();
            token = next();
            int nextCharno = stream.getCharno();
            int numSpaces = Math.max(0, nextCharno - starCharno - 1);
            for (int i = 0; i < numSpaces; i++) {
              builder.append(' ');
            }
            ignoreStar = false;
            continue;
          } else {
            // The star is part of the comment.
            if (builder.length() > 0 && builder.charAt(builder.length() - 1) != '\n') {
              builder.append(' ');
            }

            builder.append('*');
          }

          token = next();
          continue;

        case EOL:
